        @media print {
          body * { visibility: hidden; }
          .lg\\:col-span-5, .lg\\:col-span-5 * { visibility: visible; }
          .lg\\:col-span-5 { position: absolute; left: 0; top: 0; width: 100%; }
          button { display: none !important; }
