                      {['CLN', 'CHN', 'NTS'].map((t) => (
                        <button key={t} onClick={() => setLandGroup(t as LandGroup)} className={`py-2 px-1 text-sm rounded border ${landGroup === t ? 'bg-green-600 text-white border-green-600 font-bold' : 'bg-gray-50 text-gray-600 hover:bg-gray-100'}`}>
